JS_CODE = 'const questions = [\n    {\n      id: \'age\',\n      text: \'お住まいの築年数を教えてください\',\n      options: [\'築5年未満（新築・最新基準）\', \'築5〜15年\', \'築15〜25年\', \'築25〜35年\', \'築35年以上\']\n    },\n    {\n      id: \'type\',\n      text: \'住まいの種類を教えてください\',\n      options: [\'一戸建て（持ち家）\', \'マンション（持ち家）\', \'賃貸アパート・マンション\', \'一戸建て（賃貸）\']\n    },\n    {\n      id: \'insulation\',\n      text: \'断熱状況はどうですか？\',\n      options: [\'断熱材が入っていない・分からない\', \'壁のみ断熱あり\', \'壁・床・天井に断熱材あり\', \'高断熱・高気密住宅（ZEHなど）\']\n    },\n    {\n      id: \'windows\',\n      text: \'窓の種類はどれに近いですか？\',\n      options: [\'シングルガラス・アルミサッシ（昔のタイプ）\', \'ペアガラス（複層ガラス）\', \'トリプルガラス・樹脂サッシ\']\n    },\n    {\n      id: \'energy_bill\',\n      text: \'夏・冬のピーク時の月間光熱費（電気・ガス合計）はいくらですか？\',\n      options: [\'1万円未満\', \'1〜2万円\', \'2〜3万円\', \'3〜5万円\', \'5万円以上\']\n    },\n    {\n      id: \'comfort\',\n      text: \'冬の室内温度・快適さはどうですか？\',\n      options: [\'暖かく快適（不満なし）\', \'やや寒いが我慢できる\', \'かなり寒くて不快\', \'結露がひどい・健康が心配\']\n    },\n    {\n      id: \'budget\',\n      text: \'断熱リフォームにかけられる予算感はありますか？\',\n      options: [\'DIYレベル（〜10万円）\', \'部分リフォーム（10〜50万円）\', \'本格リフォーム（50〜200万円）\', \'大規模改修（200万円以上）\', \'まだ検討段階\']\n    }\n  ];\n\n  let currentStep = 0;\n  let answers = {};\n\n  function renderQuestion() {\n    const q = questions[currentStep];\n    document.getElementById(\'step-label\').textContent = `質問 ${currentStep + 1} / ${questions.length}`;\n    document.getElementById(\'progress-bar\').style.width = `${((currentStep + 1) / questions.length) * 100}%`;\n    document.getElementById(\'prev-btn\').classList.toggle(\'hidden\', currentStep === 0);\n    document.getElementById(\'next-btn\').textContent = currentStep === questions.length - 1 ? \'診断する\' : \'次へ\';\n\n    let html = `<p class="font-semibold text-gray-800 mb-4">${q.text}</p><div class="space-y-2">`;\n    q.options.forEach(opt => {\n      const checked = answers[q.id] === opt ? \'checked\' : \'\';\n      html += `<label class="flex items-center gap-3 p-3 border border-gray-200 rounded-xl cursor-pointer hover:border-teal-400 transition has-[:checked]:border-teal-500 has-[:checked]:bg-teal-50">\n        <input type="radio" name="${q.id}" value="${opt}" ${checked} class="accent-teal-600"> <span class="text-sm">${opt}</span>\n      </label>`;\n    });\n    html += \'</div>\';\n    document.getElementById(\'question-area\').innerHTML = html;\n  }\n\n  function saveAnswer() {\n    const el = document.querySelector(`input[name="${questions[currentStep].id}"]:checked`);\n    if (!el) { alert(\'選択してください\'); return false; }\n    answers[questions[currentStep].id] = el.value;\n    return true;\n  }\n\n  function nextStep() {\n    if (!saveAnswer()) return;\n    if (currentStep < questions.length - 1) { currentStep++; renderQuestion(); }\n    else showResult();\n  }\n\n  function prevStep() {\n    if (currentStep > 0) { currentStep--; renderQuestion(); }\n  }\n\n  function calcSavings() {\n    const billMap = {\'1万円未満\': 8000, \'1〜2万円\': 15000, \'2〜3万円\': 25000, \'3〜5万円\': 40000, \'5万円以上\': 60000};\n    const bill = billMap[answers.energy_bill] || 25000;\n\n    let savingRate = 0.05;\n    if (answers.age.includes(\'築35年\')) savingRate += 0.20;\n    else if (answers.age.includes(\'築25〜35年\')) savingRate += 0.15;\n    else if (answers.age.includes(\'築15〜25年\')) savingRate += 0.10;\n\n    if (answers.insulation === \'断熱材が入っていない・分からない\') savingRate += 0.15;\n    if (answers.windows.includes(\'シングルガラス\')) savingRate += 0.12;\n    if (answers.comfort.includes(\'かなり寒い\') || answers.comfort.includes(\'結露\')) savingRate += 0.08;\n\n    savingRate = Math.min(savingRate, 0.40);\n    return Math.round(bill * savingRate / 1000) * 1000;\n  }\n\n  function showResult() {\n    document.getElementById(\'quiz-section\').classList.add(\'hidden\');\n    document.getElementById(\'result-section\').classList.remove(\'hidden\');\n\n    const monthlySaving = calcSavings();\n    const annualSaving = monthlySaving * 12;\n\n    const advice = [];\n    if (answers.windows.includes(\'シングルガラス\')) advice.push(\'窓の内窓設置（インナーサッシ）は1〜3万円/窓で断熱効果が劇的に改善。補助金対象になることも多い。\');\n    if (answers.insulation === \'断熱材が入っていない・分からない\') advice.push(\'屋根・天井への断熱材追加は比較的安価（10〜30万円）で効果が高い。夏の冷房費削減にも有効。\');\n    if (answers.age.includes(\'築35年\') || answers.age.include'
